private static long countNumbersWithBits(long n, int bits, Map<Integer, Long> memo) {
    if (memo.containsKey(bits)) {
        return memo.get(bits);
    }

    long low = 1L << (bits - 1);
    long high = (1L << bits) - 1;

    if (low > n) {
        memo.put(bits, 0L);
        return 0;
    }

    long upper = Math.min(high, n);
    long count = upper - low + 1;
    memo.put(bits, count);
    return count;
}

