import java.util.*;

public static long solve(long n, long k) {
    if (k == 0) {
        return n >= 1 ? 1 : 0;
    }

    // Precompute popcount-depth for numbers up to a certain limit (since k <=5, depth up to 5)
    // We can use memoization or precompute for numbers up to a reasonable size
    // But for n up to 1e15, we need a smarter approach

    // The idea is to find numbers x in [1, n] such that the popcount sequence reaches 1 in exactly k steps
    // So, the sequence length is k+1 (including x and 1)
    // We can think of the problem as:
    // x must have popcount-depth k, meaning:
    // - The popcount-depth of popcount(x) is k-1
    // - popcount(x) must be >=1 (since it eventually reaches 1)

    // We can use dynamic programming to count numbers with popcount m and certain depth

    // Let's first handle the case when k ==1:
    // Numbers x where popcount(x) ==1, but x !=1 (since depth of 1 is 0)
    // So numbers with exactly one '1' in binary, except 1

    // For general k, we can use recursion:
    // count(n, k) = numbers x in [1, n] where depth(x) ==k
    // depth(x) = 1 + depth(popcount(x))
    // We can use memoization for popcount and depth

    // But for large n, we need a combinatorial approach

    // Let's convert n to binary string
    String binary = Long.toBinaryString(n);
    int len = binary.length();

    // We'll use digit DP to count numbers <=n with popcount-depth exactly k
    // The state will be:
    // - position in the binary string
    // - number of 1s used so far
    // - whether the number being formed is already less than n
    // We'll need to precompute the depth for all possible popcounts

    // First, precompute depth for all possible popcounts up to 60 (since 2^60 is around 1e18)
    int[] depth = new int[61];
    for (int i = 1; i <= 60; i++) {
        depth[i] = getDepth(i);
    }

    // Now, use digit DP to count numbers x <=n with depth[x] ==k
    long[][][] dp = new long[len + 1][len + 1][2];
    dp[0][0][0] = 1; // position 0, 0 1s, tight constraint

    for (int i = 0; i < len; i++) {
        for (int j = 0; j <= len; j++) {
            for (int tight = 0; tight < 2; tight++) {
                if (dp[i][j][tight] == 0) continue;

                int maxDigit = (tight == 1) ? (binary.charAt(i) - '0') : 1;
                for (int d = 0; d <= maxDigit; d++) {
                    int newJ = j + (d == 1 ? 1 : 0);
                    int newTight = (tight == 1 && d == maxDigit) ? 1 : 0;
                    dp[i + 1][newJ][newTight] += dp[i][j][tight];
                }
            }
        }
    }

    long result = 0;
    for (int j = 1; j <= len; j++) {
        if (depth[j] == k) {
            result += dp[len][j][0] + dp[len][j][1];
        }
    }

    // Special case: when k ==1, we exclude x=1
    if (k == 1) {
        if (n >= 1) {
            result--;
        }
    }

    return result;
}

private static int getDepth(int x) {
    if (x == 1) return 0;
    int pop = Integer.bitCount(x);
    return 1 + getDepth(pop);
}
