import java.util.*;

public static long solve(long n, long k) {
    if (k == 0) {
        return n == 1 ? 1 : 0;
    }

    // Precompute popcount-depth for numbers up to a certain limit (like 60 bits)
    int maxBits = 60;
    long[] depth = new long[maxBits + 1];
    depth[1] = 0;
    for (int i = 2; i <= maxBits; i++) {
        int next = Integer.bitCount(i);
        depth[i] = depth[next] + 1;
    }

    // Now, we need to count numbers x in [1, n] with popcount-depth == k
    // The idea is to find numbers x where the sequence of popcounts leads to depth k
    // We can use digit DP to count numbers up to n with exactly 'bits' set and depth[bits] == k-1

    long result = 0;
    for (int bits = 1; bits <= maxBits; bits++) {
        if (depth[bits] == k - 1) {
            result += countNumbersWithBitSet(n, bits);
        }
    }
    return result;
}

private static long countNumbersWithBitSet(long n, int targetBits) {
    String s = Long.toBinaryString(n);
    int len = s.length();
    long[][][] dp = new long[len][len + 1][2];
    for (int i = 0; i < len; i++) {
        for (int j = 0; j <= len; j++) {
            Arrays.fill(dp[i][j], -1);
        }
    }
    return dfs(s, 0, 0, true, targetBits, dp);
}

private static long dfs(String s, int index, int bits, boolean isTight, int targetBits, long[][][] dp) {
    if (index == s.length()) {
        return bits == targetBits ? 1 : 0;
    }
    int tight = isTight ? 1 : 0;
    if (dp[index][bits][tight] != -1) {
        return dp[index][bits][tight];
    }
    long res = 0;
    int maxDigit = isTight ? s.charAt(index) - '0' : 1;
    for (int d = 0; d <= maxDigit; d++) {
        boolean newIsTight = isTight && (d == maxDigit);
        int newBits = bits + (d == 1 ? 1 : 0);
        res += dfs(s, index + 1, newBits, newIsTight, targetBits, dp);
    }
    dp[index][bits][tight] = res;
    return res;
}
