import java.util.*;

public static long solve(long n, long k) {
    if (k == 0) {
        return n >= 1 ? 1 : 0;
    }

    // Precompute popcount-depth for numbers up to a certain limit (e.g., 60 bits)
    int maxBits = 60;
    int[] depth = new int[maxBits + 1];
    depth[1] = 0;
    for (int i = 2; i <= maxBits; i++) {
        int next = Integer.bitCount(i);
        depth[i] = depth[next] + 1;
    }

    // We need to count numbers x in [1, n] with depth[x] == k
    // To do this, we can use digit DP to count numbers with popcount m and depth[m] == k-1
    // So, for each possible m where depth[m] == k-1, count numbers x in [1, n] with popcount(x) == m

    long result = 0;
    for (int m = 1; m <= maxBits; m++) {
        if (depth[m] == k - 1) {
            result += countNumbersWithPopcount(n, m);
        }
    }
    return result;
}

private static long countNumbersWithPopcount(long n, int targetPopcount) {
    String binary = Long.toBinaryString(n);
    int length = binary.length();
    long[][][] dp = new long[length + 1][targetPopcount + 1][2];
    dp[0][0][0] = 1;

    for (int i = 0; i < length; i++) {
        for (int j = 0; j <= targetPopcount; j++) {
