import java.util.*;

public static long solve(long n, long k) {
    if (k == 0) {
        return n == 1 ? 1 : 0;
    }

    // Precompute popcount-depth for numbers up to a certain limit (e.g., 60 bits)
    int maxBits = 60;
    int[] depth = new int[maxBits + 1];
    depth[1] = 0;
    for (int i = 2; i <= maxBits; i++) {
        int next = Integer.bitCount(i);
        depth[i] = depth[next] + 1;
    }

    // We need to count numbers x in [1, n] where depth[bitCount(x)] == k - 1
    // because the depth of x is 1 + depth[bitCount(x)]
    int targetDepth = (int) k - 1;
    if (targetDepth < 0) {
        return 0;
    }

    // Now, we need to count numbers x in [1, n] where bitCount(x) is in the set S,
    // where S = {m | depth[m] == targetDepth}
    List<Integer> candidates = new ArrayList<>();
    for (int m = 1; m <= maxBits; m++) {
        if (depth[m] == targetDepth) {
            candidates.add(m);
        }
    }

    if (candidates.isEmpty()) {
        return 0;
    }

    // Now, the problem reduces to counting numbers x in [1, n] where bitCount(x) is in candidates
    // We can use digit DP to compute this efficiently
    String s = Long.toBinaryString(n);
    int len = s.length();
    long[][][] dp = new long[len][len + 1][2];
    for (long[][] arr2 : dp) {
        for (long[] arr1 : arr2) {
            Arrays.fill(arr1, -1);
        }
    }

    long result = 0;
    for (int m : candidates) {
        if (m > len) {
            continue;
        }
        for (long[][] arr2 : dp) {
            for (long[] arr1 : arr2) {
                Arrays.fill(arr1, -1);
            }
        }
        result += digitDP(s, 0, m, 0, dp);
    }

    return result;
}

private static long digitDP(String s, int pos, int remainingOnes, int tight, long[][][] dp) {
    if (pos == s.length()) {
        return remainingOnes == 0 ? 1 : 0;
    }
    if (dp[pos][remainingOnes][tight] != -1) {
        return dp[pos][remainingOnes][tight];
    }

    long res = 0;
    int maxDigit = tight == 1 ? (s.charAt(pos) - '0') : 1;
    for (int d = 0; d <= maxDigit; d++) {
        int newTight = (tight == 1 && d == maxDigit) ? 1 : 0;
        int newRemaining = remainingOnes - (d == 1 ? 1 : 0);
        if (newRemaining >= 0) {
            res += digitDP(s, pos + 1, newRemaining, newTight, dp);
        }
    }

    dp[pos][remainingOnes][tight] = res;
    return res;
}
