import java.util.*;

public static long solve(long n, long k) {
    if (k == 0) {
        return n == 1 ? 1 : 0;
    }

    // Precompute the popcount-depth for numbers up to a certain limit (like 60 bits)
    // Since popcount-depth decreases quickly, we can limit the precomputation
    int maxBits = 60;
    int[] depth = new int[maxBits + 1];
    depth[1] = 0;
    for (int i = 2; i <= maxBits; i++) {
        int next = Integer.bitCount(i);
        depth[i] = depth[next] + 1;
    }

    // Now, we need to count numbers x in [1, n] with depth[x] == k
    // To compute this efficiently, we can use digit DP (dynamic programming)
    // The digit DP will count numbers <= n with exactly 'k' steps to reach 1 via popcount

    String s = Long.toBinaryString(n);
    int len = s.length();
    long[][][] dp = new long[len][len + 1][2];
    for (long[][] arr2 : dp) {
        for (long[] arr1 : arr2) {
            Arrays.fill(arr1, -1);
        }
    }

    // The DP function will compute the count of numbers with exactly 'targetCount' 1s,
    // and then we'll check if their depth is equal to k
    long res = 0;
    for (int targetCount = 1; targetCount <= len; targetCount++) {
        if (depth[targetCount] + 1 == k) {
            // Reset DP for each targetCount
            for (long[][] arr2 : dp) {
                for (long[] arr1 : arr2) {
                    Arrays.fill(arr1, -1);
                }
            }
            res += digitDP(s, 0, targetCount, 0);
        }
    }
    return res;
}

private static long digitDP(String s, int pos, int remainingOnes, int tight) {
    if (pos == s.length()) {
        return remainingOnes == 0 ? 1 : 0;
    }
    if (remainingOnes < 0) {
        return 0;
    }
    if (dp[pos][remainingOnes][tight] != -1) {
        return dp[pos][remainingOnes][tight];
    }

    long res = 0;
    int limit = tight == 1 ? (s.charAt(pos) - '0') : 1;
    for (int d = 0; d <= limit; d++) {
        int newTight = (tight == 1 && d == limit) ? 1 : 0;
        int newRemaining = remainingOnes - (d == 1 ? 1 : 0);
        res += digitDP(s, pos + 1, newRemaining, newTight);
    }
    dp[pos][remainingOnes][tight] = res;
    return res;
}
